insert.foreach:
        INSERT /* @SQLID=SUB0202_0403-01#Sql001 */
        INTO CORDYS.FUND_RESERVE_SETTING (
			  BUTEN_CODE
		    , ACCOUNT_NUMBER
		    , FUND_CD_KAISU
		    , FUND_CD_GOU
		    , AZUKARI_KBN
		    , MODIFY_KBN
		    , PAYMENT_METHOD
		    , NISA_BARELY_BUYING_KBN
		    , NISA_EXCESS_BUYING_KBN
		    , SETTING_AMOUNT
		    , COURSE_KBN
		    , SETTING_RESERVE_DD
		    , SETTING_RESERVE_BIMONTHLY
		    , SETTING_RESERVE_WEEKLY
		    , SETTING_RESERVE_MULTIDAY
		    , ONE_MONTH_SUM_AMOUNT
		    , SETTING_BONUS_FLAG
		    , PAYMENT_BONUS
		    , RESERVE_MM_B1
		    , RESERVE_DD_B1
		    , RESERVE_MM_B2
		    , RESERVE_DD_B2
		    , PLAN_DATE
		    , PLAN_DATE_BONUS1
		    , PLAN_DATE_BONUS2
		    , NEXT_RESERVE_DATE
		    , KANYU_KBN
		    , UKETUKE_HOUHOU
		    , CHECK_COMP_WRN_ALERT
		    , RECEPTION_ROUTE_KBN
		    , OPERATOR_ID
		    , BROKER_CODE
		    , INTERMEDIARY_EMP_CD
		    , DELETE_KBN
		    , CREATE_TIME
		    , CREATE_USER
		    , UPDATE_TIME
		    , UPDATE_USER
		) 
    	(SELECT 
			 #{item.butenCode} 					
			, #{item.accountNumber} 			
			, #{item.mfkaisu} 					
			, #{item.mfgo} 						
			, #{item.accountType} 				
			, '3'					 			
			, '1'					 			
			, #{item.nisaBarelyBuyingType} 		
			, #{item.taxShiftType} 				
			, #{item.settingAmount} 			
			, #{item.courseType} 				
			, #{item.settingReserveDay} 		
			, #{item.settingReserveBimonthly} 	
			, #{item.settingReserveWeek} 		
			, #{item.settingReserveMultiDay} 	
			, #{item.oneMonthSumAmount} 		
			, #{item.settingBonus} 				
			, #{item.settingBonusAmount} 		
			, #{item.settingBonus1Month} 		
			, #{item.settingBonus1Day} 			
			, #{item.settingBonus2Month} 		
			, #{item.settingBonus2Day} 			
			, #{item.planDate} 					
			, #{item.bonusPlanDate1} 			
			, #{item.bonusPlanDate2} 			
			, #{item.nextReserveDate} 			
			, NULL 								
			, NULL 								
			, NULL 								
			, '2' 								
			, #{item.operatorId} 				
			, #{item.brokerCode} 				
			, #{item.intermediaryEmpCd} 		
			, '0'  								
			, IFA_DATE_UTIL.IFA_GET_DATE 		
			, #{item.createUser} 				
			, IFA_DATE_UTIL.IFA_GET_DATE 		
			, #{item.updateUser} 					
		FROM
			DUAL   	
    	)
